{% extends '@admin/default_frame.twig' %}
{% set menus = ['content', 'productoption', 'css'] %}
{% block title %}{{ 'productoption.admin.nav.content.productoption'|trans }}{% endblock %}
{% block sub_title %}{{ 'admin.content.contents_management'|trans }}{% endblock %}

{% form_theme form '@admin/Form/bootstrap_4_horizontal_layout.html.twig' %}

{% block javascript %}
    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/ace/1.2.8/ace.js\"></script>
    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/ace/1.2.8/ext-language_tools.js\"></script>
    <script>
        ace.require('ace/ext/language_tools');
        var editor = ace.edit('editor');
        editor.session.setMode('ace/mode/twig');
        editor.setTheme('ace/theme/tomorrow');
        editor.setValue('{{ form.css_html.vars.value|escape('js') }}');
        editor.setOptions({
            enableBasicAutocompletion: true,
            enableSnippets: true,
            enableLiveAutocompletion: true,
            showInvisibles: true
        });

        \$('#content_productoption_form').on('submit', function(elem) {
            \$('#product_option_design_css_html').val(editor.getValue());
        });

        var setModeAndSubmit = function(mode, keyname, keyid) {
            document.content_productoption_form.mode.value = mode;
            if(keyname !== undefined && keyname !== \"\" && keyid !== undefined && keyid !== \"\") {
                document.content_productoption_form[keyname].value = keyid;
            }
            document.content_productoption_form.submit();
        };
    </script>
{% endblock javascript %}

{% block main %}
    <form role=\"form\" class=\"form-row\" name=\"content_productoption_form\" id=\"content_productoption_form\" method=\"post\" action=\"?\">
        {{ form_widget(form._token) }}
        <input type=\"hidden\" name=\"mode\" value=\"regist\">
        <div class=\"c-contentsArea__cols\">
            <div class=\"c-contentsArea__primaryCol\">
                <div class=\"c-primaryCol\">
                    <div class=\"card rounded border-0 mb-4\">
                        <div class=\"card-header\">
                            <div class=\"row\">
                                <div class=\"col-8\"><span class=\"card-title\">{{ 'productoption.admin.content.css.title'|trans }}</span>
                                </div>
                                <div class=\"col-4 text-right\">
                                    <a data-toggle=\"collapse\" href=\"#ordererInfo\"
                                       aria-expanded=\"false\" aria-controls=\"ordererInfo\">
                                        <i class=\"fa fa-angle-up fa-lg\"></i>
                                    </a>
                                </div>
                            </div>
                        </div>
                        <div class=\"collapse show ec-cardCollapse\" id=\"blockEdit\">
                            <div class=\"card-body\">
                                <div class=\"row mb-2\">
                                    <div class=\"col-2\">
                                        <span>{{ form.children.css_html.vars.label }}</span>
                                    </div>
                                    <div class=\"col-10\">
                                        <div id=\"editor\" style=\"height: 480px\" class=\"form-control{{ has_errors(form.css_html) ? ' is-invalid' }}\"></div>
                                        <div class=\"d-none\">
                                            {{ form_widget(form.css_html) }}
                                        </div>
                                        {{ form_errors(form.css_html) }}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <div class=\"c-conversionArea\">
            <div class=\"c-conversionArea__container\">
                <div class=\"row justify-content-between align-items-center\">
                    <div class=\"col-6\">
                        <div class=\"c-conversionArea__leftBlockItem\">
                        </div>
                    </div>
                    <div class=\"col-6\">
                        <div id=\"ex-conversion-action\" class=\"row align-items-center justify-content-end\">
                            <div class=\"col-auto\">
                                <button class=\"btn btn-ec-regular\" onClick=\"setModeAndSubmit('init','','');\"
                                        type=\"button\">{{ 'productoption.admin.content.design.reset'|trans }}</button>
                            </div>
                            <div class=\"col-auto\">
                                <button class=\"btn btn-ec-conversion px-5\"
                                        type=\"submit\">{{ 'productoption.admin.common.save'|trans }}</button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </form>
{% endblock %}
", "@ProductOption/admin/Content/css.twig", "/var/www/htdocs/ec922501/app/Plugin/ProductOption/Resource/template/admin/Content/css.twig");
    }
